scwin.onpageload = function () {
  scwin.updateMblNoUnderbar();
  const codeOptions = [{
    grpCd: "IL047",
    compID: "gr_SeaAFRCont:cntrOwnerCd"
  } //정정항목
  ];
  $c.data.setCommonCode($p, codeOptions);
};
scwin.onUdcCompleted = function () {
  btn_vssl.hide();
  btn_carrier.hide();
  scwin.f_initSetTab();
  scwin.f_Set("INIT");

  //README : SCAC 코드명 길이제한이 20인데, DB에는 더 긴 데이터가 존재한다.
  // 그래서 바인딩 되어있는 dataList에 데이터가 길이만큼 잘려버려서 길이제한을 속성으로 주지 않고 사용자 입력으로 처리하도록 코드를 수정하였다. 
  //(사용자 입력으로는 20자 넘는 코드명칭 일 경우 추가입력 불가. 삭제만 가능)
  txt_scacNm.bind("editkeyup", scwin.txt_scacNm_editkeyupEvent);
};
scwin.cfViewTab = async function (index) {
  await tb_control.setSelectedTabIndex(index);
};

//---------------------------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function () {
  //$c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1,tr_tab_center2]);
  tb_control.enableTab(0);
  tb_control.enableTab(1);
  tb_control.enableTab(2);
  scwin.cfViewTab(0);
};

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
  //console.log('gubun : ' + gubun);
  switch (gubun) {
    case "INIT":
      $c.gus.cfDisableKeyData($p);
      $c.gus.cfDisableBtnOnly($p, [b_Create, b_Cancel, b_Update, b_Save, b_Delete]);
      scwin.f_DisablePopUpObj();
      gr_SeaAFRCont.setReadOnly("grid", true);
      break;
    case "RETRIEVE":
      $c.gus.cfDisableKeyData($p);
      $c.gus.cfEnableBtnOnly($p, [b_Create]);
      $c.gus.cfDisableBtnOnly($p, [b_Cancel, b_Update, b_Save, b_Delete]);
      scwin.f_DisablePopUpObj();
      gr_SeaAFRCont.setReadOnly("grid", true);
      gr_SeaAFR.setColumnReadOnly("chk", true);
      break;
    case "RETRIEVE2":
      $c.gus.cfDisableKeyData($p);
      $c.gus.cfEnableBtnOnly($p, [b_Update, b_Delete]);
      $c.gus.cfDisableBtnOnly($p, [b_Cancel, b_Create, b_Save]);
      scwin.f_DisablePopUpObj();
      gr_SeaAFRCont.setReadOnly("grid", true);
      gr_SeaAFR.setColumnReadOnly("chk", false);
      break;
    case "CREATE":
      $c.gus.cfEnableKeyData($p);
      $c.gus.cfEnableBtnOnly($p, [b_Save, b_Cancel]);
      $c.gus.cfDisableBtnOnly($p, [b_Delete, b_Update, b_Create]);
      scwin.f_EnablePopUpObj();
      gr_SeaAFRCont.setReadOnly("grid", false);
      gr_SeaAFR.setColumnReadOnly("chk", true);
      $c.gus.cfEnableObjects($p, [txt_shipperNm, txt_shipperAddr1, txt_shipperAddr2, txt_shipperAddr3, txt_shipperAddr4, txt_consigneeNm, txt_consigneeAddr1, txt_consigneeAddr2, txt_consigneeAddr3, txt_consigneeAddr4]); // B/L 정보 수정할 수 있도록 추가
      break;
    case "UPDATE":
      $c.gus.cfEnableKeyData($p);
      $c.gus.cfEnableBtnOnly($p, [b_Save, b_Delete, b_Cancel]);
      $c.gus.cfDisableBtnOnly($p, [b_Update, b_Create]);
      scwin.f_EnablePopUpObj();
      gr_SeaAFRCont.setReadOnly("grid", false);
      gr_SeaAFR.setColumnReadOnly("chk", true);
      $c.gus.cfEnableObjects($p, [txt_shipperNm, txt_shipperAddr1, txt_shipperAddr2, txt_shipperAddr3, txt_shipperAddr4, txt_consigneeNm, txt_consigneeAddr1, txt_consigneeAddr2, txt_consigneeAddr3, txt_consigneeAddr4]); // B/L 정보 수정할 수 있도록 추가
      break;
    case "DELETE":
      $c.gus.cfDisableKeyData($p);
      $c.gus.cfEnableBtnOnly($p, [b_Delete]);
      $c.gus.cfDisableBtnOnly($p, [b_Update, b_Create, b_Save, b_Cancel]);
      scwin.f_DisablePopUpObj();
      break;
  }
};

//-------------------------------------------------------------------------
// 비활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_DisablePopUpObj = function () {
  $c.gus.cfDisableObjects($p, [btn_callSign, btn_vsslNation, btn_scac, btn_orgPort, btn_shipperNation, btn_consigneeNation, btn_noty1Nation, btn_noty2Nation]);
  $c.gus.cfDisableObjects($p, [ed_etd, ed_eta, udc_discPort, udc_lodPort, udc_dlv, udc_dest]);
};

//-------------------------------------------------------------------------
// 활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function () {
  $c.gus.cfEnableObjects($p, [btn_callSign, btn_vsslNation, btn_scac, btn_orgPort, btn_shipperNation, btn_consigneeNation, btn_noty1Nation, btn_noty2Nation]);
  $c.gus.cfDisableObjects($p, [ed_etd, ed_eta, udc_discPort, udc_lodPort, udc_dlv, udc_dest]);
  $c.gus.cfDisableObjects($p, [ed_vsslCd, txt_vsslNm, ed_vygNo, ed_carrierCd, txt_carrierNm]);
  $c.gus.cfDisableObjects($p, [ed_hblno, ed_mblno2, ed_discPortCd, txt_discPortNm, ed_lodPortCd, txt_lodPortNm, ed_dlvCd, txt_dlvNm, ed_destCd, txt_destNm, ed_etd, ed_eta]);
  $c.gus.cfDisableObjects($p, [txt_shipperNm, txt_shipperAddr1, txt_shipperAddr2, txt_shipperAddr3, txt_shipperAddr4]);
  $c.gus.cfDisableObjects($p, [txt_consigneeNm, txt_consigneeAddr1, txt_consigneeAddr2, txt_consigneeAddr3, txt_consigneeAddr4]);
  $c.gus.cfDisableObjects($p, [ed_pkg, lc_unitCd, txt_grossWt, txt_msr]);
};
scwin.executeSubmission = async function (sbmObj) {
  let rtn = await $c.sbm.execute($p, sbmObj);
  let jsonRtn = rtn.responseJSON;
  let success = jsonRtn.resultDataSet[0].Code == "0";
  switch (sbmObj.org_id) {
    case "sbm_retrieve":
      scwin.f_ByteCheck();
      break;
    case "sbm_retrieve2":
      scwin.sbm_retrieve2_submitdone(success);
      break;
    case "sbm_retrieveCont":
      break;
    case "sbm_retrieveCont2":
      scwin.sbm_retrieveCont2_submitdone(success);
      break;
    case "sbm_Save":
      scwin.sbm_Save_submitdone(success);
      break;
    case "sbm_SaveCont":
      break;
    case "sbm_edisend":
      await $c.win.alert($p, "전송대기상태로 전환되었습니다.");
      break;
    case "sbm_SaveCallSign":
      await $c.win.alert($p, "저장이 완료되었습니다.");
      break;
    case "sbm_retrieveMarks":
      break;
  }
};

