scwin.f_Retrieve = async function () {
  if (ed_mblno.getValue() == "") {
    await $c.win.alert($p, "Master B/L은 필수 입력사항입니다.");
    return;
  }
  dma_Search.set("mblno", ed_mblno.getValue());
  dma_Search.set("kcomcd", "DBEX");
  await scwin.executeSubmission(sbm_retrieve);
  if (ds_SeaAFR.getCellData(0, "flag") == "1") {
    // BL에서 정보를 가져올때
    gr_SeaAFR.setReadOnly("grid", true);
    ed_dangUnNo.setValue("");
    lc_relaxYn.setValue("");
    lc_scpYn.setValue("");
    lc_completeYn.setValue("");
    scwin.f_Set("RETRIEVE");
  } else if (ds_SeaAFR.getCellData(0, "flag") == "2") {
    gr_SeaAFR.setReadOnly("grid", false);
    scwin.f_Set("RETRIEVE2");
  }
};

