//---------------------------------------------------------
//엑셀 다운로드
//---------------------------------------------------------  
scwin.f_downExcelSheet = async function (guBun) {
  let cntRow = 0;
  let testCnt = 0;
  switch (guBun) {
    case 1:
      cntRow = ds_SeaAFR.getRowCount();
      testCnt = 0;
      for (let i = 0; i < ds_SeaAFR.getRowCount(); i++) {
        if (ds_SeaAFR.getCellData(i, "flag") == "1") testCnt++;
      }
      if (cntRow != 0 && testCnt == 0) {
        let cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
          $c.data.downloadGridViewExcel($p, gr_SeaAFR, {
            fileName: "Sea AFR목록.xlsx",
            sheetName: "Sea AFR목록"
          });
        }
      } else {
        await $c.win.alert($p, "조회결과가 없거나 저장된 데이터가 아닙니다.");
      }
      break;
    case 2:
      cntRow = ds_SeaAFRCont.getRowCount();
      testCnt = 0;
      if (ds_SeaAFR.getCellData(ds_SeaAFR.getRowPosition(), "flag") == "1") testCnt++;
      if (cntRow != 0 && testCnt == 0) {
        let cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
          $c.data.downloadGridViewExcel($p, gr_SeaAFRCont, {
            fileName: "Sea AFR Container 목록.xlsx",
            sheetName: "Sea AFR Container 목록"
          });
        }
      } else {
        await $c.win.alert($p, "조회결과가 없거나 저장된 데이터가 아닙니다.");
      }
      break;
    default:
      break;
  }
};

