scwin.f_sendEDI = async function () {
  // 조회된 데이터가 있는지 검증 
  if (ds_SeaAFR.getRowCount() == 0) {
    await $c.win.alert($p, "선택된 건이 없습니다. M B/L을 먼저 조회하시기 바랍니다.");
    return;
  }

  // 체크한 데이터가 있는지 검증 
  let check = "F";
  for (let i = 0; i < ds_SeaAFR.getRowCount(); i++) {
    if (ds_SeaAFR.getCellData(i, "chk") == "T") {
      check = "T";
    }
  }
  if (check == "F") {
    await $c.win.alert($p, "선택된 건이 없습니다.");
    return;
  }
  for (let i = 0; i < ds_SeaAFR.getRowCount(); i++) {
    if (ds_SeaAFR.getCellData(i, "chk") == "T") {
      ds_SeaAFR.setCellData(ds_SeaAFR.getRowPosition(), "sendYn", "0");
    }
  }
  await scwin.executeSubmission(sbm_edisend);
  await scwin.executeSubmission(sbm_retrieve);
};

