// 입력된 문자열의 바이트 수를 계산하여 byteObj에 "XX Byte" 형식으로 표시하는 함수
scwin.updateByteStr = function (inputObj, byteObj) {
  let str = inputObj.getValue();
  byteObj.setValue(scwin.getByteLength(str) + " Byte");
};
scwin.getByteLength = function (str) {
  let byteLength = 0;
  for (let i = 0; i < str.length; i++) {
    let ch = str.charCodeAt(i);
    // 한글(가~힣, ㄱ~ㅎ, ㅏ~ㅣ) 및 기타 EUC-KR 2바이트 문자 처리
    if (ch >= 0xAC00 && ch <= 0xD7A3 ||
    // 가~힣
    ch >= 0x3131 && ch <= 0x318E ||
    // ㄱ~ㅎ, ㅏ~ㅣ
    ch >= 0x1100 && ch <= 0x11FF // 한글 자모
    ) {
      byteLength += 2;
    } else if (ch > 0x007F) {
      // 기타 비ASCII 문자도 2바이트 처리 (EUC-KR)
      byteLength += 2;
    } else {
      byteLength += 1;
    }
  }
  return byteLength;
};
