scwin.ds_SeaAFR_ondataload = async function () {
  scwin.clickRow = 0;
  let rowcnt = ds_SeaAFR.getRowCount();
  if (rowcnt == 0) {
    await $c.win.alert($p, E_MSG_CM_WRN_002);
    return;
  }
  ds_SeaAFR.setRowPosition(0);
  let targetColIndex = gr_SeaAFR.getColumnIndex("hblno");
  gr_SeaAFR.setFocusedCell(0, targetColIndex);
  if (ds_SeaAFR.getCellData(ds_SeaAFR.getRowPosition(), "flag") == "1") {
    if (ed_callSignCd.getValue() != "") {
      scwin.f_PopUp('CallSignCd', 'T', 'F', 'F');
    }
  }
  scwin.f_ByteCheck();
  txt_gr_SeaAFR_count.setValue(ds_SeaAFR.getRowCount());
  await scwin.f_RetrieveCont(0);
};
scwin.ds_SeaAFRMarks_ondataload = function (e) {
  let rowcnt = ds_SeaAFRMarks.getRowCount();
  if (rowcnt != 0) {
    let markVal = ds_SeaAFRMarks.getCellData(ds_SeaAFRMarks.getRowPosition() || 0, "mark");
    let Split = markVal.split("\n");
    if (Split[0] != undefined) txt_mark1.setValue(Split[0]);
    if (Split[1] != undefined) txt_mark2.setValue(Split[1]);
    if (Split[2] != undefined) txt_mark3.setValue(Split[2]);
    if (Split[3] != undefined) txt_mark4.setValue(Split[3]);
  }
};
scwin.ds_SeaAFR_onrowpositionchange = async function (info) {
  // Mark 조회
  let row = info.newRowIndex;
  if (ds_SeaAFR.getCellData(row, "flag") == "1") {
    dma_Search2.set("hblno", ds_SeaAFR.getCellData(row, "hblno"));
    dma_Search2.set("mblno", ds_SeaAFR.getCellData(row, "mblno"));
    dma_Search2.set("mhno", ds_SeaAFR.getCellData(row, "mhno"));
    dma_Search2.set("kcomcd", "DBEX");
    await scwin.executeSubmission(sbm_retrieveMarks);
  }
  scwin.f_ByteCheck();
  txt_gr_SeaAFRCont_count.setValue(gr_SeaAFRCont.getRowCount());
};
scwin.ds_SeaAFR_oncelldatachange = function (info) {
  let colID = info.colID;
  switch (colID) {
    case "shipperNm":
    case "shipperAddr1":
    case "shipperAddr2":
    case "shipperAddr3":
    case "shipperAddr4":
    case "shipperComm":
    case "consigneeNm":
    case "consigneeAddr1":
    case "consigneeAddr2":
    case "consigneeAddr3":
    case "consigneeAddr4":
    case "consigneeComm":
    case "noty1Nm":
    case "noty1Addr1":
    case "noty1Addr2":
    case "noty1Addr3":
    case "noty1Addr4":
    case "noty1Comm":
    case "noty2Nm":
    case "noty2Addr1":
    case "noty2Addr2":
    case "noty2Addr3":
    case "noty2Addr4":
    case "noty2Comm":
      scwin.f_ByteCheck();
      break;
  }
};
